import{_ as s}from"./chunks/figure-3-retest-confirmation.j9u8p4tG.js";import{_ as n}from"./chunks/figure-4-post-entry-exit-paths.ByVbamFl.js";import{_ as e,o as t,c as p,a1 as l}from"./chunks/framework.BKJzsOC1.js";const v=JSON.parse('{"title":"第六章：③、资金流与持仓管理","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/06-flow-and-position-management.md","filePath":"trading/intraday-entry/06-flow-and-position-management.md"}'),i={name:"trading/intraday-entry/06-flow-and-position-management.md"};function o(d,a,c,r,h,u){return t(),p("div",null,[...a[0]||(a[0]=[l(`<h1 id="第六章-3、资金流与持仓管理" tabindex="-1">第六章：③、资金流与持仓管理 <a class="header-anchor" href="#第六章-3、资金流与持仓管理" aria-label="Permalink to &quot;第六章：③、资金流与持仓管理&quot;">​</a></h1><blockquote><p>价格结构负责触发和否决，Prem/Vol 负责提供辅助证据；没有结构确认，资金流不能单独建仓。</p></blockquote><h2 id="一、先把3说清楚" tabindex="-1">一、先把③说清楚 <a class="header-anchor" href="#一、先把3说清楚" aria-label="Permalink to &quot;一、先把③说清楚&quot;">​</a></h2><p><code>③</code>不是指标名称，也不是固定的第三根 K 线，而是三步价格结构的第三阶段：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 突破关键位</span></span>
<span class="line"><span>→ ② 回踩并守住</span></span>
<span class="line"><span>→ ③ 突破回踩结构，再次向原方向启动</span></span></code></pre></div><p>以做多为例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>关键线：7500</span></span>
<span class="line"><span>① 价格突破并收在 7504</span></span>
<span class="line"><span>② 回踩到 7501，但没有重新被接受在旧区间</span></span>
<span class="line"><span>③ 向上突破回踩过程的小高点，例如 7506</span></span></code></pre></div><p><img src="`+s+`" alt="突破回踩教学图：①突破、②回踩、③再次启动"></p><p>③之所以是第一个可执行确认，是因为此时可以同时写出：</p><ul><li>方向：市场重新向哪一侧启动；</li><li>失效：做多看②的回踩低点，做空看②的反抽高点；</li><li>目标：下一节点、前高低或流动性区域是否还有空间。</li></ul><p>空头完全对称：跌破支撑后反抽不过，③向下跌破反抽结构的小低点，才进入做空评估。</p><p>没有②就没有③；只有影线刺穿、没有实体收在触发位外侧，也不算清楚的③。</p><h2 id="二、prem和vol分别说明什么" tabindex="-1">二、Prem和Vol分别说明什么 <a class="header-anchor" href="#二、prem和vol分别说明什么" aria-label="Permalink to &quot;二、Prem和Vol分别说明什么&quot;">​</a></h2><p><code>Vol</code>表示成交了多少张合约，说明市场活跃程度；<code>Prem</code>表示成交金额或平台估算的权利金规模，更接近资金强度。不同平台对净权利金的统计方式可能不同，因此应把它们视为辅助估计，而不是对“新开方向性仓位”的直接证明。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vol大、Prem不明显增加 → 活跃，但方向信息有限</span></span>
<span class="line"><span>Prem增加、价格未确认 → 关注度增加，但不能建仓</span></span>
<span class="line"><span>价格确认、Prem持续同向 → 交易可信度加分</span></span>
<span class="line"><span>价格失效、Prem仍然很高 → 价格拥有否决权</span></span></code></pre></div><p>资金流可能混入对冲、平仓、价差、滚仓和远虚值合约。单根巨大柱子不能替代价格结构。</p><h2 id="三、资金流在三个阶段的权限" tabindex="-1">三、资金流在三个阶段的权限 <a class="header-anchor" href="#三、资金流在三个阶段的权限" aria-label="Permalink to &quot;三、资金流在三个阶段的权限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>价格必须先完成的事</th><th>Prem/Vol的作用</th><th>执行动作</th></tr></thead><tbody><tr><td>建仓前</td><td>突破、收线、②回踩、③再次启动</td><td>提高关注度、辅助确认</td><td>没有③不建主要仓位</td></tr><tr><td>持仓中</td><td>守住②的结构极值和关键位</td><td>判断趋势是否仍有支持</td><td>结构完整可持有；加仓仍等新结构</td></tr><tr><td>准备退出</td><td>跌破失效点或反抽失败</td><td>提供风险背景</td><td>价格失效就减仓或退出</td></tr></tbody></table><h3 id="建仓前" tabindex="-1">建仓前 <a class="header-anchor" href="#建仓前" aria-label="Permalink to &quot;建仓前&quot;">​</a></h3><p>即使 Call Prem 上升、Put Prem 下降，也要等待：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>突破关键线</span></span>
<span class="line"><span>→ 1分钟收线站稳</span></span>
<span class="line"><span>→ 回踩守住</span></span>
<span class="line"><span>→ ③再次启动</span></span></code></pre></div><p>如果只是第一根突破 K 线，或者价格仍在关键位中间反复，资金流只能作为观察信号。</p><h3 id="持仓中" tabindex="-1">持仓中 <a class="header-anchor" href="#持仓中" aria-label="Permalink to &quot;持仓中&quot;">​</a></h3><p>一根小阴线不等于多单失效。重点看：</p><ul><li>是否守住②的回踩低点；</li><li>回踩量能是否缩小；</li><li>价格是否仍在关键线或 VWAP 的有利一侧；</li><li>Call Prem 是否保持，Put Prem 是否没有连续反向增加。</li></ul><p>继续持有不等于立即加仓。加仓仍需要新的回踩和新的③，并且原仓止损已经能够上移或风险已经下降。</p><h3 id="准备退出" tabindex="-1">准备退出 <a class="header-anchor" href="#准备退出" aria-label="Permalink to &quot;准备退出&quot;">​</a></h3><p>如果价格已经跌破②的回踩低点，或者跌回关键线后反抽失败，即使 Call Prem 仍处于高位，也不能继续扛单。资金流可能滞后，或反映的是组合交易而非单纯方向性多单。</p><blockquote><p>价格失效时，Prem/Vol只能解释背景，不能否决退出。</p></blockquote><h2 id="四、正常回踩和真正失效" tabindex="-1">四、正常回踩和真正失效 <a class="header-anchor" href="#四、正常回踩和真正失效" aria-label="Permalink to &quot;四、正常回踩和真正失效&quot;">​</a></h2><p><img src="`+n+`" alt="建仓后的四种路径：影线测试、结构失效、时间失效和盈利后形成新结构"></p><h3 id="正常回踩" tabindex="-1">正常回踩 <a class="header-anchor" href="#正常回踩" aria-label="Permalink to &quot;正常回踩&quot;">​</a></h3><p>做多时，正常回踩通常有以下特征：</p><ul><li>影线测试关键线，但实体重新收回；</li><li>没有跌破②的回踩低点；</li><li>回踩量能缩小；</li><li>下一次上攻突破回踩小高点。</li></ul><p>这时不应因为一根红 K 立即退出。</p><h3 id="真正失效" tabindex="-1">真正失效 <a class="header-anchor" href="#真正失效" aria-label="Permalink to &quot;真正失效&quot;">​</a></h3><p>做多时，失效通常按以下顺序变得清楚：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>跌回关键线下</span></span>
<span class="line"><span>→ 跌破②回踩低点</span></span>
<span class="line"><span>→ 反抽不能站回关键线</span></span>
<span class="line"><span>→ 形成更低高点</span></span>
<span class="line"><span>→ 放量继续下跌</span></span></code></pre></div><p>不需要等所有条件都出现：预设硬止损被触发时直接执行；结构已经破坏时主动减仓或退出；反抽失败后不重新抄底。</p><p>空单完全反过来：关注②的反抽高点、关键线重新站回以及更高低点是否形成。</p><h2 id="五、一个完整的执行例子" tabindex="-1">五、一个完整的执行例子 <a class="header-anchor" href="#五、一个完整的执行例子" aria-label="Permalink to &quot;五、一个完整的执行例子&quot;">​</a></h2><p>假设 SPX 5 分钟处于上升环境，1 分钟突破 7500：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 收线到 7504：方向候选出现</span></span>
<span class="line"><span>② 回踩到 7501，最低没有持续跌入旧区间：结构仍有效</span></span>
<span class="line"><span>③ 突破 7506：做多触发</span></span>
<span class="line"><span>入场：7506附近，或③收线后的微回踩</span></span>
<span class="line"><span>失效：②回踩低点下方，并结合旧区间重新接受的位置</span></span>
<span class="line"><span>目标：下一节点或前高，先检查剩余空间是否值得承担风险</span></span></code></pre></div><p>如果价格已经从 7506 直接拉到 7518，距离失效点变远、距离下一目标变近，即使③曾经出现，也不应因为害怕错过而追价。</p><h2 id="六、执行卡" tabindex="-1">六、执行卡 <a class="header-anchor" href="#六、执行卡" aria-label="Permalink to &quot;六、执行卡&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>关键线：</span></span>
<span class="line"><span>① 突破是否完成：</span></span>
<span class="line"><span>② 回踩/反抽是否守住：</span></span>
<span class="line"><span>③ 是否突破回踩结构并再次启动：</span></span>
<span class="line"><span>做多失效：②回踩低点下方 / 重新接受旧区间</span></span>
<span class="line"><span>做空失效：②反抽高点上方 / 重新接受旧区间</span></span>
<span class="line"><span>Prem是否持续同向：</span></span>
<span class="line"><span>Vol是否与价格同向：</span></span>
<span class="line"><span>第一目标与剩余空间：</span></span></code></pre></div><p>本章只保留一个核心优先级：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>价格触发 → Flow确认 → 结构完整则持有 → 价格失效先退出</span></span></code></pre></div><p>资金流是加分项，不是买卖按钮；③是执行确认，不是结果保证。</p>`,49)])])}const k=e(i,[["render",o]]);export{v as __pageData,k as default};
